/* Helper to check if sensors are fresh (within timeout window) */
static bool are_sensors_fresh(const controller_t *controller, uint32_t now_ms)
{
    bool turbidity_fresh = false;
    bool level_fresh = false;

    if (controller->has_valid_turbidity &&
        (now_ms >= controller->last_turbidity_ms &&
         (now_ms - controller->last_turbidity_ms) <= CONTROLLER_SENSOR_TIMEOUT_MS)) {
        turbidity_fresh = true;
    }
    if (controller->has_valid_level &&
        (now_ms >= controller->last_level_ms &&
         (now_ms - controller->last_level_ms) <= CONTROLLER_SENSOR_TIMEOUT_MS)) {
        level_fresh = true;
    }

    return turbidity_fresh && level_fresh;
}

/* Helper to check sensor timeout and force safe idle */
static void check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    bool turbidity_stale = !controller->has_valid_turbidity ||
        (now_ms >= controller->last_turbidity_ms &&
         (now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);
    bool level_stale = !controller->has_valid_level ||
        (now_ms >= controller->last_level_ms &&
         (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);

    if (turbidity_stale || level_stale) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
    }
}

/* Helper to transition to filtering state */
static void enter_filtering(controller_t *controller)
{
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->clear_streak_count = 0;
}

/* Helper to transition to settling state */
static void enter_settling(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = now_ms;
}

/* Helper to transition to draining state */
static void enter_draining(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

/* Helper to transition to complete state */
static void enter_complete(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Check for sensor timeout first - this takes priority */
    check_sensor_timeout(controller, input.now_ms);

    /* If in safe idle due to timeout, return with changed flag */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE && !controller->has_valid_turbidity ||
        controller->state == CONTROLLER_STATE_SAFE_IDLE && !controller->has_valid_level) {
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        return output;
    }

    /* Process input based on current state */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Wait for both sensors to be valid before proceeding */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;
        } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
            controller->has_valid_level = true;
            controller->last_level = input.level;
            controller->last_level_ms = input.now_ms;
        }

        /* Only transition out of SAFE_IDLE when both sensors are valid */
        if (controller->has_valid_turbidity && controller->has_valid_level) {
            if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                enter_filtering(controller);
            } else {
                enter_complete(controller);
            }
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Handle turbidity input - update streak count */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;

            if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller->clear_streak_count++;
            } else {
                controller->clear_streak_count = 0;
            }

            /* Check if we have enough clear samples to settle */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->has_valid_level &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                enter_settling(controller, input.now_ms);
            }
        }

        /* Check level for complete condition */
        if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            enter_complete(controller);
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        /* Check settling duration */
        bool settling_done = false;
        if ((input.now_ms >= controller->settling_started_ms + CONTROLLER_SETTLING_MS)) {
            settling_done = true;
        }

        /* Handle turbidity input - check for disturbance */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;

            /* Disturbance during settling - return to filtering */
            if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                enter_filtering(controller);
            } else if (settling_done && controller->has_valid_level &&
                       controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Settling complete, transition to draining */
                enter_draining(controller);
            }
        }

        /* Check level for complete condition */
        if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            enter_complete(controller);
        }

        /* If settling done and all conditions met, go to draining */
        if (settling_done && !controller->has_valid_turbidity ||
            (settling_done && controller->has_valid_turbidity &&
             controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
             controller->has_valid_level &&
             controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL)) {
            enter_draining(controller);
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        /* Handle turbidity input - check for disturbance */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;

            /* Disturbance during draining - close drain and restart filtering */
            if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                controller->has_valid_level &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                enter_filtering(controller);
            }
        }

        /* Check level for complete condition */
        if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            enter_complete(controller);
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* Stay in complete until sensors timeout or new input arrives */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;

            /* If level recovers above minimum, can restart filtering */
            if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
                controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                enter_filtering(controller);
            }
        } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
            controller->has_valid_level = true;
            controller->last_level = input.level;
            controller->last_level_ms = input.now_ms;

            /* If level recovers above minimum, can restart filtering */
            if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
                controller->has_valid_turbidity &&
                controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                enter_filtering(controller);
            }
        }
        break;

    default:
        controller_set_safe_idle(controller);
        break;
    }

    /* Handle timeout inputs */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

